        *(&out_re[5*K+k]) = (A1r-t1r); *(&out_im[5*K+k]) = (A1i-t1i);
        *(&out_re[2*K+k]) = (A2r+B2i); *(&out_im[2*K+k]) = (A2i-B2r);
        *(&out_re[6*K+k]) = (A2r-B2i); *(&out_im[6*K+k]) = (A2i+B2r);
        const double t3r = (vnc*(B3r-B3i)), t3i = (vnc*(B3r+B3i));
        *(&out_re[3*K+k]) = (A3r+t3r); *(&out_im[3*K+k]) = (A3i+t3i);
        *(&out_re[7*K+k]) = (A3r-t3r); *(&out_im[7*K+k]) = (A3i-t3i);
